script:
frappe.ui.form.on('Leave Application', {
	refresh(frm) {
		const isApprover = frm.doc.leave_approver === frappe.session.user;
		const isSystemManager = frappe.user.has_role('System Manager');
		const canEdit = isApprover || isSystemManager;

		frm.set_df_property('status', 'read_only', canEdit ? 0 : 1);
	},
});
